import java.util.HashMap;

public int maxFrequencyScore(int[] nums, int k) {
    int n = nums.length;
    int right = 0, count = 0, max_score = 0;
    long score = 0;
    HashMap<Integer, Integer> freqMap = new HashMap<Integer, Integer>();

    for (int left = 0; left < n; ++left) {
        while (right < n && count < k) {
            score = (score + (long)nums[right] * freqMap.getOrDefault(nums[right], 0)) % 1000000007;
            freqMap.put(nums[right], freqMap.getOrDefault(nums[right], 0) + 1);
            count++;
            right++;
        }

        max_score = Math.max(max_score, (int)score);

        if (count == k) {
            score -= nums[left] * (freqMap.get(nums[left]) - 1);
            freqMap.put(nums[left], freqMap.get(nums[left]) - 1);
            count--;
        }
    }

    return max_score;
}
```

    1. Initialize variables `right`, `count`, `max_score`, and `score`.
2. Use a hash map `freq_map` to store the frequency of each number in the subarray.
3. Use a sliding window of size `k` to traverse through the array:
   a. Move the right pointer and increment the count and update score.
   b. When the count becomes equal to `k`:
       - Calculate the score and compare with the current max score. If the score is greater, update the max score.
       - Move the left pointer and decrement the count.
4. Return `max_score`.

The time complexity is O(n) and the space complexity is also O(n), where n is the length of the nums array.
